const setup = $('⚙️ Setup').first().json;
const mail = $('📬 Neue Kunden-E-Mail (IMAP)').item.json;
const von = mail.from || '';
const betreff = mail.subject || '(kein Betreff)';
const text = (mail.textPlain || mail.textHtml || '').toString().slice(0, 4000);

// Absender-E-Mail aus dem From-Feld extrahieren
const m = von.toString().match(/[\w.+-]+@[\w-]+\.[\w.]+/);
const kundeEmail = m ? m[0] : '';

const prompt = 'Du bist der Kundenservice des Onlineshops "' + setup.SHOP_NAME + '". ' +
  (setup.ANSPRACHE === 'du' ? 'Duze den Kunden.' : 'Sieze den Kunden.') + '\n\n' +
  'Shop-Infos:\n- Versandzeit: ' + setup.VERSANDZEIT + '\n- Rueckgaberecht: ' + setup.RETOURE_TAGE + ' Tage\n\n' +
  'Eingegangene Kunden-E-Mail:\nVon: ' + von + '\nBetreff: ' + betreff + '\n\n' + text + '\n\n' +
  'Aufgaben:\n' +
  '1. Klassifiziere die E-Mail: versand | retoure | produktfrage | beschwerde | sonstiges\n' +
  '2. Entscheide, ob ein Mensch uebernehmen muss (braucht_mensch = "ja" bei: Rechtsthemen, Drohungen, Rueckbuchungen/Chargebacks, sehr wuetenden Kunden, individuellen Sonderfaellen, oder wenn du Bestelldaten braeuchtest die du nicht hast). Standardfragen (Versandzeit, Retoure-Ablauf, allgemeine Produktfragen) beantwortest du selbst.\n' +
  '3. Schreibe eine freundliche, hilfreiche Antwort-E-Mail auf Deutsch als sauberes HTML (Inline-CSS, kurz und klar). Erfinde KEINE Fakten, keine Tracking-Nummern, keine Bestelldetails.\n\n' +
  'Antworte NUR mit validem JSON, ohne Markdown-Codeblock:\n' +
  '{"kategorie": "...", "braucht_mensch": "ja|nein", "betreff": "Re: ...", "antwort_html": "..."}';

return { json: { kunde_email: kundeEmail, original_betreff: betreff, original_text: text.slice(0, 800), prompt: prompt } };

const blocks = $json.content || [];
const text = (blocks.find(b => b.type === 'text') || {}).text || '';
let daten;
try {
  daten = JSON.parse(text.replace(/```json|```/g, '').trim());
} catch (e) {
  daten = { kategorie: 'sonstiges', braucht_mensch: 'ja', betreff: 'Re: Ihre Anfrage', antwort_html: text };
}
const orig = $('🧠 Prompt bauen').item.json;
const setup = $('⚙️ Setup').first().json;

const telegram_text = '🚨 KUNDENSERVICE - Mensch gebraucht!\n\n' +
  'Von: ' + orig.kunde_email + '\n' +
  'Kategorie: ' + daten.kategorie + '\n' +
  'Betreff: ' + orig.original_betreff + '\n\n' +
  'Nachricht:\n' + orig.original_text + '\n\n' +
  '--- Claude-Entwurf (nicht gesendet) ---\n' +
  (daten.antwort_html || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').slice(0, 1200);

const empfaenger = setup.TEST_MODE === 'ja' ? setup.OWNER_EMAIL : orig.kunde_email;

return { json: {
  braucht_mensch: daten.braucht_mensch === 'ja' ? 'ja' : 'nein',
  kategorie: daten.kategorie,
  empfaenger: empfaenger,
  betreff: (setup.TEST_MODE === 'ja' ? '[TEST] ' : '') + (daten.betreff || 'Re: ' + orig.original_betreff),
  antwort_html: daten.antwort_html || '',
  telegram_text: telegram_text
}};
